from geometry import Color

def hex_color(color: Color) -> str:
    if color == Color.RED:
        return "#FF0000"
    elif color == Color.GREEN:
        return "#00FF00"
    elif color == Color.BLUE:
        return "#0000FF"
    return "#000000"

def mix_colors(c1: Color, c2: Color) -> str:
    return f"Mixed {c1} and {c2}"

def format_area(area: float) -> str:
    return f"{area:.2f}"

