    print(f"Total area: {format_area(total)}")

    # Color utilities
    print(f"Red hex: {hex_color(Color.RED)}")

    # Enum value (prints as PascalCase)
    print(Color.BLUE)

    # Shape info
    print(f"Count: {renderer.get_count()}")
